solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int data[20]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    int minVal = data[0];
    int maxVal = data[0];
    for (int i = 1; i < n; ++i) {
        if (data[i] < minVal) minVal = data[i];
        if (data[i] > maxVal) maxVal = data[i];
    }

    std::cout << "Min: " << minVal << '\n';
    std::cout << "Max: " << maxVal << '\n';
    return 0;
}

