solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int data[10]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    for (int i = n - 1; i >= 0; --i) {
        if (i < n - 1) std::cout << ' ';
        std::cout << data[i];
    }
    std::cout << '\n';
    return 0;
}
